def _load_config(path: str) -> Dict[str, Any]:
    with open(path, "r", encoding="utf-8") as f:
        return json.load(f)


def _tenant_specs_from_config(cfg: Dict[str, Any]) -> List[TenantSpec]:
    tenants = []
