    p.add_argument("--insecure", action="store_true", help="Disable TLS verification")
    p.add_argument("--timeout", type=int, default=int(os.getenv("RABBITMQ_API_TIMEOUT", "20")))
    p.add_argument("--retries", type=int, default=int(os.getenv("RABBITMQ_API_RETRIES", "5")))
