def _plan_actions(tenants: List[TenantSpec]) -> List[Tuple[str, Dict[str, Any]]]:
    actions: List[Tuple[str, Dict[str, Any]]] = []
    for t in tenants:
        actions.append(("ensure_vhost", {"vhost": t.vhost, "tags": t.vhost_tags}))
